# Initialize AWS clients
s3_client = boto3.client('s3')
sns_client = boto3.client('sns')
rekognition_client = boto3.client('rekognition')
cloudwatch_client = boto3.client('cloudwatch')

# Configuration from environment variables
RESULTS_BUCKET = os.environ.get('RESULTS_BUCKET', 'my-image-results-bucket')
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN', '')
CONFIDENCE_THRESHOLD = float(os.environ.get('CONFIDENCE_THRESHOLD', '80.0'))
SUPPORTED_FORMATS = {'.jpg', '.jpeg', '.png', '.bmp', '.gif'}


class ImageProcessingError(Exception):
    """Custom exception for image processing failures."""
    pass


def validate_image_key(key):
    """Validate that the uploaded file is a supported image format."""
    lower_key = key.lower()
    for fmt in SUPPORTED_FORMATS:
        if lower_key.endswith(fmt):
            return True
    return False


def get_image_from_s3(bucket, key):
    """Download image from S3 and return the object."""
    logger.info(f"Fetching image from s3://{bucket}/{key}")
    try:
        response = s3_client.get_object(Bucket=bucket, Key=key)
        image_content = response['Body'].read()
        content_type = response.get('ContentType', 'unknown')
        content_length = response.get('ContentLength', 0)

        logger.info(f"Successfully fetched image: type={content_type}, size={content_length} bytes")

        return {
            'content': image_content,
            'content_type': content_type,
            'content_length': content_length,
            'metadata': response.get('Metadata', {})
        }
    except s3_client.exceptions.NoSuchKey:
        logger.error(f"Image not found: s3://{bucket}/{key}")
        raise ImageProcessingError(f"Image not found: s3://{bucket}/{key}")
    except Exception as e:
        logger.error(f"Error fetching image from S3: {str(e)}")
        raise


def detect_labels(bucket, key):
    """Use AWS Rekognition to detect labels in the image."""
    logger.info(f"Running Rekognition label detection on s3://{bucket}/{key}")
    try:
        response = rekognition_client.detect_labels(
            Image={
                'S3Object': {
                    'Bucket': bucket,
                    'Name': key
                }
            },
            MaxLabels=20,
            MinConfidence=CONFIDENCE_THRESHOLD
        )

        labels = []
        for label in response.get('Labels', []):
            label_info = {
                'name': label['Name'],
                'confidence': round(label['Confidence'], 2),
                'categories': [cat['Name'] for cat in label.get('Categories', [])],
                'instances': len(label.get('Instances', [])),
                'parents': [p['Name'] for p in label.get('Parents', [])]
            }
            labels.append(label_info)

        logger.info(f"Detected {len(labels)} labels")
        return labels

    except rekognition_client.exceptions.InvalidS3ObjectException:
        logger.error(f"Rekognition cannot access the S3 object: s3://{bucket}/{key}")
        raise ImageProcessingError("Rekognition cannot access the image")
    except rekognition_client.exceptions.ImageTooLargeException:
        logger.error(f"Image too large for Rekognition: s3://{bucket}/{key}")
        raise ImageProcessingError("Image exceeds Rekognition size limits")
    except Exception as e:
        logger.error(f"Rekognition error: {str(e)}")
        raise


def detect_moderation_labels(bucket, key):
    """Check image for inappropriate content."""
    logger.info(f"Running content moderation on s3://{bucket}/{key}")
    try:
        response = rekognition_client.detect_moderation_labels(
            Image={
                'S3Object': {
                    'Bucket': bucket,
                    'Name': key
                }
            },
            MinConfidence=CONFIDENCE_THRESHOLD
        )

        moderation_labels = []
        for label in response.get('ModerationLabels', []):
            moderation_labels.append({
                'name': label['Name'],
                'confidence': round(label['Confidence'], 2),
                'parent': label.get('ParentName', '')
            })

        is_safe = len(moderation_labels) == 0
        logger.info(f"Content moderation result: safe={is_safe}, flags={len(moderation_labels)}")

        return {
            'is_safe': is_safe,
            'moderation_labels': moderation_labels
        }

    except Exception as e:
        logger.error(f"Moderation detection error: {str(e)}")
        raise


def write_results_to_s3(source_key, results):
    """Write processing results as JSON to the results S3 bucket."""
    timestamp = datetime.utcnow().strftime('%Y%m%d_%H%M%S')
    base_name = os.path.splitext(os.path.basename(source_key))[0]
    result_key = f"results/{base_name}/{timestamp}_{uuid.uuid4().hex[:8]}.json"

    result_body = json.dumps(results, indent=2, default=str)

    logger.info(f"Writing results to s3://{RESULTS_BUCKET}/{result_key}")
    try:
        s3_client.put_object(
            Bucket=RESULTS_BUCKET,
            Key=result_key,
            Body=result_body,
            ContentType='application/json',
            Metadata={
                'source-bucket': results.get('source_bucket', ''),
                'source-key': source_key,
                'processed-at': timestamp
            }
        )
        logger.info(f"Results written successfully to s3://{RESULTS_BUCKET}/{result_key}")
        return result_key
    except Exception as e:
        logger.error(f"Error writing results to S3: {str(e)}")
        raise


def send_sns_notification(subject, message, message_attributes=None):
    """Send an SNS notification about the processing result."""
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not configured, skipping notification")
        return None

    logger.info(f"Sending SNS notification: {subject}")
    try:
        params = {
            'TopicArn': SNS_TOPIC_ARN,
            'Subject': subject[:100],  # SNS subject limit
            'Message': message
        }
        if message_attributes:
            params['MessageAttributes'] = message_attributes

        response = sns_client.publish(**params)
        message_id = response.get('MessageId')
        logger.info(f"SNS notification sent: MessageId={message_id}")
        return message_id
    except Exception as e:
        logger.error(f"Error sending SNS notification: {str(e)}")
        # Don't raise - notification failure shouldn't fail the whole process
        return None


def publish_custom_metrics(processing_time_ms, label_count, is_safe, success):
    """Publish custom CloudWatch metrics for monitoring."""
    try:
        metrics = [
            {
                'MetricName': 'ImagesProcessed',
                'Value': 1,
                'Unit': 'Count',
                'Dimensions': [
                    {'Name': 'Status', 'Value': 'Success' if success else 'Failure'}
                ]
            },
            {
                'MetricName': 'ProcessingTimeMs',
                'Value': processing_time_ms,
                'Unit': 'Milliseconds'
            },
            {
                'MetricName': 'LabelsDetected',
                'Value': label_count,
                'Unit': 'Count'
            }
        ]

        if not is_safe:
            metrics.append({
                'MetricName': 'UnsafeContentDetected',
                'Value': 1,
                'Unit': 'Count'
            })

        cloudwatch_client.put_metric_data(
            Namespace='ImageProcessing',
            MetricData=metrics
        )
        logger.info("Custom metrics published to CloudWatch")
    except Exception as e:
        logger.warning(f"Failed to publish custom metrics: {str(e)}")


def process_image(source_bucket, source_key):
    """Main image processing pipeline."""
    start_time = datetime.utcnow()
    logger.info(f"Starting image processing pipeline for s3://{source_bucket}/{source_key}")

    # Step 1: Validate the image format
    if not validate_image_key(source_key):
        raise ImageProcessingError(
            f"Unsupported image format: {source_key}. Supported: {SUPPORTED_FORMATS}"
        )

    # Step 2: Verify the image exists and get metadata
    image_data = get_image_from_s3(source_bucket, source_key)

    # Step 3: Run content moderation
    moderation_result = detect_moderation_labels(source_bucket, source_key)

    # Step 4: Detect labels/objects in the image
    labels = detect_labels(source_bucket, source_key)

    # Step 5: Compile results
    processing_time = (datetime.utcnow() - start_time).total_seconds() * 1000

    results = {
        'source_bucket': source_bucket,
        'source_key': source_key,
        'processed_at': datetime.utcnow().isoformat(),
        'processing_time_ms': round(processing_time, 2),
        'image_metadata': {
            'content_type': image_data['content_type'],
            'content_length': image_data['content_length'],
            'user_metadata': image_data['metadata']
        },
        'content_moderation': moderation_result,
        'labels': labels,
        'label_count': len(labels),
        'top_labels': [l['name'] for l in sorted(labels, key=lambda x: x['confidence'], reverse=True)[:5]],
        'status': 'completed'
    }

    # Step 6: Write results to S3
    result_key = write_results_to_s3(source_key, results)
    results['result_key'] = result_key

    # Step 7: Send SNS notification
    notification_subject = f"Image Processed: {os.path.basename(source_key)}"

    if not moderation_result['is_safe']:
        notification_subject = f"[MODERATION FLAG] {notification_subject}"

    notification_message = json.dumps({
        'event': 'image_processed',
        'source': f"s3://{source_bucket}/{source_key}",
        'results': f"s3://{RESULTS_BUCKET}/{result_key}",
        'label_count': len(labels),
        'top_labels': results['top_labels'],
        'is_safe': moderation_result['is_safe'],
        'processing_time_ms': results['processing_time_ms']
    }, indent=2)

    message_attributes = {
        'event_type': {
            'DataType': 'String',
            'StringValue': 'image_processed'
        },
        'is_safe': {
            'DataType': 'String',
            'StringValue': str(moderation_result['is_safe'])
        }
    }

    send_sns_notification(notification_subject, notification_message, message_attributes)

    # Step 8: Publish custom metrics
    publish_custom_metrics(
        processing_time_ms=processing_time,
        label_count=len(labels),
        is_safe=moderation_result['is_safe'],
        success=True
    )

    logger.info(f"Image processing completed successfully in {processing_time:.2f}ms")
    return results


def lambda_handler(event, context):
    """
    AWS Lambda handler for S3 image upload events.
    
    Triggered by S3 PutObject events. Processes uploaded images through
    a pipeline that includes content moderation, label detection, and
    result storage with notifications.
    
    Environment Variables:
        RESULTS_BUCKET: S3 bucket for storing processing results
        SNS_TOPIC_ARN: SNS topic ARN for notifications
        CONFIDENCE_THRESHOLD: Minimum confidence for label detection (default: 80.0)
    """
    logger.info(f"Lambda invoked. Request ID: {context.aws_request_id}")
    logger.info(f"Event: {json.dumps(event, default=str)}")

    results = []
    errors = []

    # Handle S3 event records
    records = event.get('Records', [])

    if not records:
        # Support direct invocation with bucket/key
        if 'bucket' in event and 'key' in event:
            records = [{
                's3': {
                    'bucket': {'name': event['bucket']},
                    'object': {'key': event['key']}
                }
            }]
        else:
            logger.error("No records found in event and no direct invocation parameters")
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'No image references found in event'})
            }

    for record in records:
        try:
            # Extract S3 bucket and key from the event
            s3_info = record.get('s3', {})
            source_bucket = s3_info.get('bucket', {}).get('name', '')
            source_key = unquote_plus(s3_info.get('object', {}).get('key', ''))

            if not source_bucket or not source_key:
                logger.warning(f"Skipping record with missing bucket/key: {record}")
                continue

            # Skip processing of results (avoid infinite loops)
            if source_key.startswith('results/'):
                logger.info(f"Skipping results file: {source_key}")
                continue

            result = process_image(source_bucket, source_key)
            results.append(result)

        except ImageProcessingError as e:
            error_msg = f"Image processing error: {str(e)}"
            logger.error(error_msg)
            errors.append(error_msg)

            # Send failure notification
            send_sns_notification(
                subject="Image Processing Failed",
                message=json.dumps({
                    'event': 'processing_failed',
                    'source': f"s3://{source_bucket}/{source_key}",
                    'error': str(e)
                })
            )

            publish_custom_metrics(
                processing_time_ms=0,
                label_count=0,
                is_safe=True,
                success=False
            )

        except Exception as e:
            error_msg = f"Unexpected error processing record: {str(e)}"
            logger.exception(error_msg)
            errors.append(error_msg)

            send_sns_notification(
                subject="Image Processing Error",
                message=json.dumps({
                    'event': 'processing_error',
                    'error': str(e),
                    'request_id': context.aws_request_id
                })
            )

            publish_custom_metrics(
                processing_time_ms=0,
                label_count=0,
                is_safe=True,
                success=False
            )

    response = {
        'statusCode': 200 if not errors else 207,
        'body': json.dumps({
            'request_id': context.aws_request_id,
            'processed': len(results),
            'errors': len(errors),
            'results': [
                {
                    'source_key': r['source_key'],
                    'result_key': r.get('result_key', ''),
                    'label_count': r['label_count'],
                    'top_labels': r['top_labels'],
                    'is_safe': r['content_moderation']['is_safe'],
                    'processing_time_ms': r['processing_time_ms']
                }
                for r in results
            ],
            'error_messages': errors
        }, default=str)
    }

    logger.info(f"Lambda execution complete. Processed: {len(results)}, Errors: {len(errors)}")
    return response